function make(inner: string): React.FC<IconProps> {
  const C = ({ className }: IconProps) => (
    <svg
      viewBox="0 0 24 24"
      fill="none"
      className={className}
      aria-hidden="true"
      dangerouslySetInnerHTML={{ __html: inner }}
    />
  );
  C.displayName = "MingcuteIcon";
  return C;
}

